// SPDX-License-Identifier: ISC
//! Replay of frozen mining, network info, mixing, and profiler RPC
//! handler vectors generated by an in-package dump test running
//! inside dcrd's internal/rpcserver package at release-v2.1.5: 44
//! cases across generate, getgenerate, gethashespersec, setgenerate,
//! getnetworkhashps (the work summation over headers with a scripted
//! timestamp ramp), getmininginfo (nesting the getnetworkhashps
//! handler), getnetworkinfo, getmixmessage, getmixpairrequests,
//! sendrawmixmessage (the lazy hex decode semantics where trailing
//! junk past the message is never observed), startprofiler,
//! stopprofiler, and stop.  Each case carries the marshalled request
//! params (parsed here through the ported dcrjson pipeline exactly
//! like dcrd's dispatch does, jsonrpcdefaults included), the mock
//! seam facts, and the marshalled result or the exact error code and
//! message.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chaincfg::{mainnet_params, simnet_params};
use dcroxide_chainhash::Hash;
use dcroxide_dcrjson::{GoType, GoValue, RPCError, Registry, gojson, parse_params};
use dcroxide_rpc::handlers;
use dcroxide_rpc::helpers::NoInterfaces;
use dcroxide_rpc::server::{
    Config, GenerateFailure, RpcAddrManager, RpcBestState, RpcChain, RpcConnManager, RpcCpuMiner,
    RpcMixPooler, RpcNetworkInfo, RpcProfilerManager, RpcSubsidyParams, RpcSyncManager,
    RpcTimeSource, RpcTxMempooler, Server,
};
use dcroxide_rpctypes::chainsvrresults as results;
use dcroxide_rpctypes::{method, register_all};
use dcroxide_standalone::SubsidyCache;
use dcroxide_txscript::stdaddr;
use dcroxide_wire::{BlockHeader, MIX_VERSION, Message, MsgMixPairReq, decode_message_payload};

const VECTORS: &str = include_str!("data/rpchandlers9_vectors.txt");

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).unwrap()
}

/// Split a JSON array into the raw JSON text of its elements.
fn split_json_array(data: &str) -> Vec<String> {
    let bytes = data.as_bytes();
    assert_eq!(bytes.first(), Some(&b'['), "params must be an array");
    let mut elems = Vec::new();
    let mut depth = 0i32;
    let mut in_string = false;
    let mut escaped = false;
    let mut start = None;
    for (i, &b) in bytes.iter().enumerate() {
        if in_string {
            if escaped {
                escaped = false;
            } else if b == b'\\' {
                escaped = true;
            } else if b == b'"' {
                in_string = false;
            }
            continue;
        }
        match b {
            b'"' => {
                in_string = true;
                if start.is_none() {
                    start = Some(i);
                }
            }
            b'[' | b'{' => {
                if depth > 0 && start.is_none() {
                    start = Some(i);
                }
                depth += 1;
            }
            b']' | b'}' => {
                depth -= 1;
                if depth == 0 {
                    if let Some(s) = start {
                        elems.push(data[s..i].trim().to_string());
                    }
                    break;
                }
            }
            b',' if depth == 1 => {
                if let Some(s) = start {
                    elems.push(data[s..i].trim().to_string());
                }
                start = None;
            }
            b' ' | b'\t' | b'\n' | b'\r' => {}
            _ => {
                if depth == 1 && start.is_none() {
                    start = Some(i);
                }
            }
        }
    }
    elems
}

fn err_or(field: &str) -> Result<(), String> {
    match field.strip_prefix("ERR:") {
        Some(err) => Err(err.to_string()),
        None => Ok(()),
    }
}

/// The scripted chain: block 432,100 facts with a timestamp ramp on
/// the header lookups (mirroring the dump's stateful mock).
struct MockChain9 {
    header: BlockHeader,
    best_height: i64,
    block_hash: Result<(), String>,
    header_by_hash: Result<(), String>,
    header_calls: u32,
}

impl RpcChain for MockChain9 {
    fn best_snapshot(&mut self) -> RpcBestState {
        RpcBestState {
            hash: self.header.block_hash(),
            prev_hash: self.header.prev_block,
            height: self.best_height,
            bits: self.header.bits,
            next_stake_diff: 14428162590,
            total_subsidy: 1122503888072909,
            block_size: u64::from(self.header.size),
            num_txns: 7,
        }
    }
    fn block_hash_by_height(&mut self, _height: i64) -> Result<Hash, String> {
        self.block_hash.clone().map(|()| self.header.block_hash())
    }
    fn header_by_hash(&mut self, _hash: &Hash) -> Result<BlockHeader, String> {
        self.header_by_hash.clone().map(|()| {
            let mut h = self.header;
            h.timestamp = self.header.timestamp + self.header_calls * 300;
            self.header_calls += 1;
            h
        })
    }
}

/// The scripted CPU miner.
struct MockMiner {
    generate: Result<Vec<Hash>, GenerateFailure>,
    is_mining: bool,
    hashes_per_second: f64,
    workers: i32,
}

impl RpcCpuMiner for MockMiner {
    fn generate_n_blocks(&mut self, _n: u32) -> Result<Vec<Hash>, GenerateFailure> {
        self.generate.clone()
    }
    fn is_mining(&mut self) -> bool {
        self.is_mining
    }
    fn hashes_per_second(&mut self) -> f64 {
        self.hashes_per_second
    }
    fn num_workers(&mut self) -> i32 {
        self.workers
    }
    fn set_num_workers(&mut self, _workers: i32) {}
}

